refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
image = imresize(image, [120 160]);
gray = rgb2gray(image);
volume = cat(3, gray, imtranslate(gray, [3 0]), imtranslate(gray, [6 0]));
labels = zeros(size(volume));
labels(30:90, 40:120, 1:3) = 1;
props = imregionprops3(labels);
disp(props(1).Volume);
